// Filter for low price (<$0.10) + high volume (>$50K) markets
const WEBHOOK_URL = $env.WEBHOOK_URL || 'http://localhost:3000';
const MAX_PRICE = 0.10;
const MIN_VOLUME = 50000;

const marketsRaw = $input.first().json;
const markets = Array.isArray(marketsRaw) ? marketsRaw : [marketsRaw];

const results = [];

for (const market of markets) {
  try {
    const outcomePrices = JSON.parse(market.outcomePrices || '[0, 0]');
    const clobTokenIds = JSON.parse(market.clobTokenIds || '["", ""]');
    const yesPrice = parseFloat(outcomePrices[0]) || 0;
    const volume = parseFloat(market.volume || '0');

    if (yesPrice > 0 && yesPrice < MAX_PRICE && volume > MIN_VOLUME) {
      const potential = (1 / yesPrice).toFixed(0);

      results.push({
        json: {
          webhookUrl: WEBHOOK_URL + '/api/alert',
          payload: {
            category: 'risk_reward',
            title: `Long shot: "${market.question}" at $${yesPrice.toFixed(2)} with $${Math.round(volume).toLocaleString()} volume. ${potential}x if it hits.`,
            body: `Long shot opportunity: "${market.question}" is trading at $${yesPrice.toFixed(2)} (YES) with $${Math.round(volume).toLocaleString()} total volume. That's a potential ${potential}x return if it resolves YES.`,
            market: {
              conditionId: market.conditionId,
              question: market.question || 'Unknown market',
              tokenId: clobTokenIds[0] || '',
              currentPrice: yesPrice
            },
            urgent: false,
            metadata: {
              yesPrice: yesPrice,
              volume: volume,
              potentialMultiple: parseInt(potential)
            }
          }
        }
      });
    }
  } catch (e) {
    // Skip markets with malformed outcomePrices
  }
}

if (results.length === 0) {
  return [];
}

// Sort by potential multiple (highest first), limit to top 5
results.sort((a, b) => b.json.payload.metadata.potentialMultiple - a.json.payload.metadata.potentialMultiple);
return results.slice(0, 5);
